def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, fill_value=np.inf, dtype=float)
    n = len(bins)
    for i in range(n):
        capacity = bins[i]
        if capacity == 0:
            continue
        ratio = item / capacity
        if ratio > 1:
            continue
        elif ratio == 1:
            priorities[i] = 0
            continue
        score = 0
        for m in range(1, 21):
            power_val = ratio ** m
            if m % 3 == 0:
                score += power_val / (m ** 1.5)
            elif m % 2 == 0:
                score -= power_val / (m * 2)
            else:
                score += ((-1) ** m) * power_val / m
        adj_factor = 1.0
        if capacity < item * 1.2:
            adj_factor *= 2.5
        elif capacity < item * 1.8:
            adj_factor *= 2.0
        elif capacity < item * 2.5:
            adj_factor *= 1.5
        else:
            adj_factor *= 1.0 + (capacity / (item * 10))
        penalty = 0
        for offset in range(-2, 3):
            idx = i + offset
            if 0 <= idx < n and bins[idx] != 0:
                overlap = item / bins[idx]
                if 0 < overlap < 1:
                    penalty += (1 - overlap) ** 3
        penalty /= 5
        for l in range(i):
            if bins[l] != 0 and bins[l] != capacity:
                diff = abs(bins[l] - capacity) / max(bins[l], capacity)
                if diff < 0.2:
                    penalty += diff * 0.5
        score = -score * adj_factor + penalty
        if score < 0:
            score = 0
        priorities[i] = score
    min_priority = np.min(priorities[np.isfinite(priorities)])
    priorities = np.where(priorities == np.inf, min_priority + 1, priorities)
    return priorities
